import 'package:flutter_test/flutter_test.dart'; import 'package:googlepro/features/file_transfer/service/mime_type_helper.dart'; void main() { group('MimeTypeHelper', () { test('pdf extension returns correct mime', () { expect(MimeTypeHelper.fromExtension('.pdf'), 'application/pdf'); }); test('jpg returns image mime', () { expect(MimeTypeHelper.fromExtension('.jpg'), 'image/jpeg'); }); test('isImage returns true for image mime', () { expect(MimeTypeHelper.isImage('image/png'), true); }); test('unknown extension returns octet-stream', () { expect(MimeTypeHelper.fromExtension('.xyz'), 'application/octet-stream'); }); }); }